  1	import * as React from 'react';
  2	import { Slider, SliderOnChangeEvent, Tooltip, TooltipPosition } from '@patternfly/react-core';
  3	import { KialiIcon } from 'config/KialiIcon';
  4	import { ToolbarDropdown } from 'components/Dropdown/ToolbarDropdown';
  5	import { infoStyle } from 'styles/IconStyle';
  6	
  7	type TraceLimitProps = {
  8	  asRadio?: boolean;
  9	  initialLimit?: number;
 10	  onLimitChange: (limit: number) => void;
 11	  title?: string;
 12	  titleClassName?: string;
 13	};
 14	
 15	export const TRACE_LIMIT_DEFAULT = 100;
 16	export type TraceLimitOption = 20 | 100 | 500 | 1000;
 17	
 18	export const TraceLimit: React.FC<TraceLimitProps> = (props: TraceLimitProps) => {
 19	  const initialLimit = props.initialLimit ?? TRACE_LIMIT_DEFAULT;
 20	  const [limit, setLimit] = React.useState<number>(initialLimit);
 21	  const [value, setValue] = React.useState<number>(initialLimit);
 22	
 23	  const onLimitChange = (limitStr: string): void => {
 24	    const limit = parseInt(limitStr);
 25	    props.onLimitChange(limit);
 26	    setLimit(limit);
 27	  };
 28	
 29	  const tooltip = (
 30	    <Tooltip
 31	      key="tooltip_limit_per_query"
 32	      position={TooltipPosition.right}
 33	      content={
 34	        <div style={{ textAlign: 'left' }}>
 35	          <div>
 36	            This limits the number of traces that will be fetched. Each trace may have several spans. If the number of
 37	            fetched traces does not sufficiently cover the desired time period, increase the limit or reduce the time
 38	            period. Query time may increase for larger limits and/or time periods. A custom time period may also be
 39	            used.
 40	          </div>
 41	        </div>
 42	      }
 43	    >
 44	      <KialiIcon.Info className={infoStyle} />
 45	    </Tooltip>
 46	  );
 47	
 48	  const traceLimits: { [key: string]: string } = {
 49	    20: '20 traces',
 50	    100: '100 traces',
 51	    500: '500 traces',
 52	    1000: '1000 traces'
 53	  };
 54	
 55	  const handleRelease = (): void => {
 56	    if (value !== limit) {
 57	      props.onLimitChange(value);
 58	      setLimit(value);
 59	    }
 60	  };
 61	
 62	  const traceLimitComponent = (
 63	    <div>
 64	      <div style={{ marginTop: '0.5rem' }}>
 65	        <span className={props.titleClassName} style={{ paddingRight: 0 }}>
 66	          {props.title} ({value})
 67	        </span>
 68	        {tooltip}
 69	      </div>
 70	      <div id="trace-limit" onMouseUp={handleRelease} style={{ padding: '0 10px' }}>
 71	        <Slider
 72	          value={value}
 73	          onChange={(_event: SliderOnChangeEvent, value: number) => {
 74	            setValue(value);
 75	          }}
 76	          min={10}
 77	          max={1000}
 78	          step={10}
 79	        />
 80	      </div>
 81	    </div>
 82	  );
 83	
 84	  const traceLimitDropdownComponent = (
 85	    <span>
 86	      <ToolbarDropdown
 87	        id="trace-limit-dropdown"
 88	        handleSelect={onLimitChange}
 89	        nameDropdown={props.title}
 90	        nameDropdownClassName={props.titleClassName}
 91	        value={limit}
 92	        label={traceLimits[limit]}
 93	        options={traceLimits}
 94	      />
 95	      {tooltip}
 96	    </span>
 97	  );
 98	
 99	  return props.asRadio ? traceLimitComponent : traceLimitDropdownComponent;
100	};

